      "severity": "info",
      "references": ["CLIENT", "costs", "sales"]
    },
    {
      "text": "All manufacturing and delivery will be the responsibility of BOSCH.",
      "severity": "info",
      "references": ["BOSCH", "manufacturing", "delivery"]
    }
  ],
  "favoursWhom": "non-operator" 
}

